  readonly endpoint:  EndpointConfig;
  readonly payload:   TPayload;
}

type RequestResult<TPayload, TResponse> =
  | { status: "fulfilled";    requestId: string; clientId: ClientId; payload: TPayload; response: TResponse; tokensRemaining: number }
  | { status: "rate_limited"; requestId: string; clientId: ClientId; payload: TPayload; retryAfterMs: number }
  | { status: "rejected";     requestId: string; clientId: ClientId; payload: TPayload; error: string };

type FetchFn<TPayload, TResponse> = (req: ApiRequest<TPayload>) => Promise<TResponse>;

// --- Main entry point ---
async function dispatchBatch<TPayload, TResponse>(
  requests:  ReadonlyArray<ApiRequest<TPayload>>,
  fetchFn:   FetchFn<TPayload, TResponse>,
  registry:  RateLimiterRegistry
): Promise<DispatchReport<TPayload, TResponse>>

// Key types and main orchestrator signature

type OperatorExecutor<O extends PlanOperator> =
  (operator: O, rows: ReadonlyArray<Row>, registry: TableRegistry)
    => Result<ReadonlyArray<Row>, QueryError>;

type ExecutorRegistry = {
  [K in OperatorKind]: OperatorExecutor<Extract<PlanOperator, { kind: K }>>;
};

// Discriminated operator union (one variant shown):
interface FilterOperatorNode { readonly kind: "filter"; readonly clause: FilterClause; }
interface ScanOperator       { readonly kind: "scan";   readonly table: TableName; }
// … + project | groupBy | sort | limit

// Top-level orchestrator — compose all four stages:
function runQuery(
  raw: unknown,
  registry: TableRegistry
): Result<QueryReport, QueryError>;

// Core discriminated union — channel is the discriminant
type NotificationPayload =
  | { channel: "email";   to: string; subject: string; body: string }
  | { channel: "sms";     to: string; body: string }
  | { channel: "push";    deviceToken: string; title: string; body: string }
  | { channel: "webhook"; url: string; eventType: string; data: Record<string, string | number | boolean> };

// Generic handler constrained to one variant
type ChannelHandler<T extends NotificationPayload> = (payload: T) => Promise<DeliveryResult>;

// Mapped registry — Extract picks the right variant per key
type HandlerRegistry = {
  [K in NotificationPayload["channel"]]: ChannelHandler<
    Extract<NotificationPayload, { channel: K }>
  >;
};

// Validate unknown → NotificationPayload or throw
function validatePayload(raw: unknown): NotificationPayload { ... }

// Fan-out to handlers concurrently, aggregate into a report
async function routeNotifications(
  rawPayloads: unknown[],
  registry: HandlerRegistry
): Promise<DispatchReport> { ... }

// Key types at a glance

type WorkflowStep =
  | HttpStep        // { kind: "http";      url, method, body?, dependsOn }
  | TransformStep   // { kind: "transform"; expression, dependsOn }
  | ConditionStep   // { kind: "condition"; predicate, thenStepId, elseStepId, dependsOn }
  | DelayStep;      // { kind: "delay";     ms, dependsOn }

// Mapped type: each step kind → a strongly-typed async handler
type StepHandlerMap = {
  [K in WorkflowStep["kind"]]: (
    step: Extract<WorkflowStep, { kind: K }>,
    ctx: ExecutionContext
  ) => Promise<unknown>;
};

// Result monad used throughout
type Result<T, E> = { ok: true; value: T } | { ok: false; error: E };

// Main entry point
async function runWorkflow(
  rawWorkflow: unknown,       // validated at runtime
  handlers:    StepHandlerMap,
  config:      ExecutorConfig // { concurrency, maxRetries, retryBaseMs }
): Promise<ExecutionReport>
